        host_b[i] = (float)(N - i) * 0.01f;
    }

    hipMalloc(&a, N * sizeof(float));
    hipMalloc(&b, N * sizeof(float));
    hipMalloc(&partial, blocks * sizeof(float));

    hipMemcpy(a, host_a, N * sizeof(float), hipMemcpyHostToDevice);
    hipMemcpy(b, host_b, N * sizeof(float), hipMemcpyHostToDevice);

    hipLaunchKernelGGL(dot_kernel, dim3(blocks), dim3(THREADS), 0, 0, a, b, partial);
    hipDeviceSynchronize();

    hipMemcpy(host_partial, partial, blocks * sizeof(float), hipMemcpyDeviceToHost);

    // Sum partial results on CPU
    float gpu_sum = 0.0f;
    for (int i = 0; i < blocks; i++) gpu_sum += host_partial[i];

    // CPU reference
    float cpu_sum = 0.0f;
    for (int i = 0; i < N; i++) cpu_sum += host_a[i] * host_b[i];

    float err = fabsf(gpu_sum - cpu_sum);
    printf("GPU sum: %f, CPU sum: %f, Error: %e\n", gpu_sum, cpu_sum, err);

    printf("===OUTPUT_BEGIN===\n");
    printf("{\"gpu_sum\": %f, \"cpu_sum\": %f, \"max_error\": %e, \"status\": \"%s\"}\n",
           gpu_sum, cpu_sum, err, err < 1e-3 ? "pass" : "fail");
    printf("===OUTPUT_END===\n");

    hipFree(a); hipFree(b); hipFree(partial);
    return 0;
}

