    printf("===OUTPUT_END===\n");

    // Cleanup
    for (int s = 0; s < NUM_STREAMS; s++) {
        cudaFree(a[s]); cudaFree(b[s]); cudaFree(c[s]);
        cudaStreamDestroy(streams[s]);
    }
    return 0;
}

